function solve(nums) {
    const n = nums.length;
    const ans = new Array(2 * n);

    // First half: ans[i] = nums[i]
    for (let i = 0; i < n; i++) {
        ans[i] = nums[i];
    }

    // Second half: ans[i + n] = nums[n - i - 1]
    for (let i = 0; i < n; i++) {
        ans[i + n] = nums[n - 1 - i];
    }

    return ans;
}
